<?php
if ( ! current_user_can( 'creditrack_manage_backups' ) ) { wp_die( 'Access denied.', '', array( 'response' => 403 ) ); }
$jobs = $wpdb->get_results( "SELECT j.*,u.display_name FROM {$wpdb->prefix}ct_jobs j LEFT JOIN {$wpdb->users} u ON u.ID=j.created_by WHERE j.type IN ('manual','scheduled','pre-restore') ORDER BY j.created_at DESC LIMIT 100" );
?><div class="ct-titlebar"><div><h1>Backups</h1><div class="ct-muted">Integrity-checked CrediTrack data, settings, and protected documents.</div></div><form method="post" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_create_backup"><button type="submit">Create backup</button></form></div><div class="ct-alert error"><strong>Host-level backups remain the primary disaster-recovery layer.</strong> Restoration replaces current CrediTrack application data.</div><div class="ct-table-wrap"><table><thead><tr><th>Created</th><th>Type</th><th>Status</th><th>Size</th><th>Created by</th><th>Action</th></tr></thead><tbody><?php foreach ( $jobs as $job ) { ?><tr><td><?php echo esc_html( $job->created_at ); ?></td><td><?php echo esc_html( $job->type ); ?></td><td><span class="ct-badge"><?php echo esc_html( $job->status ); ?></span></td><td><?php echo esc_html( $job->file_size ? size_format( $job->file_size ) : '—' ); ?></td><td><?php echo esc_html( $job->display_name ); ?></td><td><?php if ( 'completed' === $job->status ) { $url = wp_nonce_url( add_query_arg( array( 'action'=>'creditrack_download_backup','backup_id'=>$job->id ), admin_url( 'admin-post.php' ) ), 'creditrack_download_backup' ); ?><a class="ct-button secondary" href="<?php echo esc_url( $url ); ?>">Download</a><?php } ?></td></tr><?php } if ( ! $jobs ) { ?><tr><td colspan="6">No application backups have been created.</td></tr><?php } ?></tbody></table></div><section class="ct-card"><h2>Restore an application backup</h2><p>This creates a pre-restore backup, verifies every archive checksum and schema version, then restores inside a database transaction where supported.</p><form class="ct-form" method="post" enctype="multipart/form-data" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_restore_backup"><div class="ct-field"><label for="backup">CrediTrack ZIP backup</label><input id="backup" type="file" name="backup" accept="application/zip" required></div><div class="ct-field"><label for="restore_password">Your current password</label><input id="restore_password" type="password" name="current_password" autocomplete="current-password" required></div><div class="ct-field full"><label for="confirmation">Type RESTORE CREDITRACK</label><input id="confirmation" name="confirmation" required autocomplete="off"></div><div><button class="ct-danger-button" type="submit" data-confirm="This will replace all current CrediTrack application data. Continue?">Validate and restore</button></div></form></section>
